const detectRecursiveMemoryGrowth = (items: n8n.INodeExecutionData[][]): boolean => {
  const memorySizes = items.map(item => 
    JSON.stringify(item[0]?.json?.memory || {}).length
  );

  if (memorySizes.length < 3) return false;

  const growthRate = memorySizes[memorySizes.length - 1] / memorySizes[0];
  const consecutiveGrowth = memorySizes.slice(-3).every((size, idx) => 
    idx === 0 || size > memorySizes[idx - 1]
  );

  return growthRate > 2 && consecutiveGrowth;
};

const detectStaleContext = (memory: any[]): boolean => {
  const SESSION_WINDOW_HOURS = 1;
  const now = new Date();
  const threshold = new Date(now.getTime() - SESSION_WINDOW_HOURS * 60 * 60 * 1000);

  return memory.some(entry => {
    const timestamp = new Date(entry.timestamp || entry.createdAt);
    return timestamp < threshold && entry.role !== 'system';
  });
};

const detectCredentialExposure = (content: string): string[] => {
  const patterns = [
    /(?i)(?:api[-_]?key|secret|token|password)[\s:=]+['"][^'"]{20,}['"]/g,
    /(?:sk[-_])?[a-zA-Z0-9]{48}/g,
    /xoxb-[0-9a-zA-Z-]+/g
  ];

  const findings: string[] = [];
  patterns.forEach(pattern => {
    const matches = content.match(pattern);
    if (matches) findings.push(...matches);
  });

  return findings;
};

