const truncateMemoryWindow = (items: n8n.INodeExecutionData[][]): n8n.INodeExecutionData[][] => {
  const MAX_MESSAGES = 10;
  const item = items[0];

  if (!item[0]?.json?.memory) return items;

  const memory = item[0].json.memory as any[];
  const recentMemory = memory.slice(-MAX_MESSAGES);

  item[0].json.memory = recentMemory;
  item[0].json.memoryTruncated = memory.length > MAX_MESSAGES;

  return items;
};

// Add as first node after trigger to generate session context
const generateSessionContext = (items: n8n.INodeExecutionData[][]): n8n.INodeExecutionData[][] => {
  const sessionId = $execution.id + '-' + Date.now();
  items[0][0].json.session = {
    id: sessionId,
    startedAt: new Date().toISOString(),
    maxAgeMs: 60 * 60 * 1000 // 1 hour
  };
  return items;
};

// Sanitize function for Code node before memory storage
const sanitizeMemoryContent = (memory: any[]): any[] => {
  const SENSITIVE_PATTERNS = [/api[-_]?key/gi, /secret/gi, /token/gi];

  return memory.map(entry => ({
    ...entry,
    content: SENSITIVE_PATTERNS.reduce((text, pattern) => 
      text.replace(pattern, '[REDACTED]'), 
      entry.content || ''
    )
  }));
};

