import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  webhookSecret: process.env.VEX_WEBHOOK_SECRET!,
  detectors: ['n8n-memory-growth', 'n8n-stale-context', 'n8n-credential-exposure'],
  autoRemediate: true
});

// n8n Code node after AI Agent - Vex integration
const monitorAgentMemory = async (items: n8n.INodeExecutionData[][]): Promise<n8n.INodeExecutionData[][]> => {
  const payload = items[0][0].json;

  // Send to Vex for analysis
  const results = await vex.analyze({
    workflowId: $workflow.id,
    executionId: $execution.id,
    memoryPayload: payload.memory,
    agentOutput: payload.output
  });

  if (results.issues.length > 0) {
    // Vex auto-applies fixes
    items[0][0].json.vexRemediated = results.fixedIssues;
    items[0][0].json.memory = results.cleanedMemory;
  }

  return items;
};
